require_once __DIR__ . '/hr_organization_lib.php'; require_login(); gt_run_org_migrations($pdo); $userId=(int)$_SESSION['user_id']; if(!gt_is_hr_allowed($pdo,$userId)){http_response_code(403); exit('Acesso reservado a RH.');}
$flashSuccess=$flashError=null; if($_SERVER['REQUEST_METHOD']==='POST'){ if(!validate_csrf_or_abort(false))$flashError='Pedido inválido.'; else try{ $uid=(int)$_POST['user_id'];$mid=(int)$_POST['machine_id'];$lvl=(int)$_POST['level'];$ass=$_POST['assessed_at']?:date('Y-m-d');$exp=$_POST['expiry_date']?:null; if($exp && $exp<$ass) throw new RuntimeException('Validade não pode ser anterior à avaliação.'); $old=$pdo->prepare('SELECT * FROM hr_machine_competencies WHERE user_id=? AND machine_id=? AND deleted_at IS NULL');$old->execute([$uid,$mid]);$before=$old->fetch(PDO::FETCH_ASSOC)?:[]; $up=$pdo->prepare('UPDATE hr_machine_competencies SET level=?,assessed_at=?,expiry_date=?,training=?,limitations=?,evidence=?,notes=?,assessed_by_user_id=?,updated_by=?,updated_at=CURRENT_TIMESTAMP WHERE user_id=? AND machine_id=? AND deleted_at IS NULL');$up->execute([$lvl,$ass,$exp,trim($_POST['training']??''),trim($_POST['limitations']??''),trim($_POST['evidence']??''),trim($_POST['notes']??''),$userId,$userId,$uid,$mid]); if(!$up->rowCount()) $pdo->prepare('INSERT INTO hr_machine_competencies(user_id,machine_id,level,assessed_at,expiry_date,training,limitations,evidence,notes,assessed_by_user_id,created_by,updated_by) VALUES (?,?,?,?,?,?,?,?,?,?,?,?)')->execute([$uid,$mid,$lvl,$ass,$exp,trim($_POST['training']??''),trim($_POST['limitations']??''),trim($_POST['evidence']??''),trim($_POST['notes']??''),$userId,$userId,$userId]); gt_org_audit($pdo,$userId,'hr.skills.upsert','hr_machine_competencies',$mid,$before,$_POST); $flashSuccess='Competência gravada.';}catch(Throwable $e){$flashError='Erro: '.$e->getMessage();}}
$people=$pdo->query('SELECT id,name,department,schedule_id FROM users WHERE COALESCE(is_active,1)=1 ORDER BY name')->fetchAll(PDO::FETCH_ASSOC);$machines=$pdo->query("SELECT * FROM erp_machines WHERE deleted_at IS NULL AND status<>'inactive' ORDER BY code")->fetchAll(PDO::FETCH_ASSOC);$q=trim($_GET['q']??'');$mid=(int)($_GET['machine_id']??0);$uid=(int)($_GET['user_id']??0);$lvl=($_GET['level']??'');$where=['c.deleted_at IS NULL'];$args=[]; if($q!==''){$where[]='(u.name LIKE ? OR m.code LIKE ? OR m.name LIKE ?)';$args[]="%$q%";$args[]="%$q%";$args[]="%$q%";} if($mid){$where[]='c.machine_id=?';$args[]=$mid;} if($uid){$where[]='c.user_id=?';$args[]=$uid;} if($lvl!==''){$where[]='c.level=?';$args[]=(int)$lvl;} $st=$pdo->prepare('SELECT c.*,u.name user_name,u.department,m.code machine_code,m.name machine_name,m.operators_required FROM hr_machine_competencies c JOIN users u ON u.id=c.user_id JOIN erp_machines m ON m.id=c.machine_id WHERE '.implode(' AND ',$where).' ORDER BY u.name,m.code');$st->execute($args);$rows=$st->fetchAll(PDO::FETCH_ASSOC);$uncovered=$pdo->query("SELECT COUNT(*) FROM erp_machines m WHERE m.deleted_at IS NULL AND m.status<>'inactive' AND NOT EXISTS(SELECT 1 FROM hr_machine_competencies c JOIN users u ON u.id=c.user_id WHERE c.machine_id=m.id AND c.level>=3 AND c.deleted_at IS NULL AND COALESCE(u.is_active,1)=1)")->fetchColumn();
$pageTitle='Matriz de competências'; require __DIR__.'/partials/header.php'; ?>
<div class="container-fluid py-4"><?php if($flashSuccess):?><div class="alert alert-success"><?=h($flashSuccess)?></div><?php endif;?><?php if($flashError):?><div class="alert alert-danger"><?=h($flashError)?></div><?php endif;?><form class="card card-body mb-3"><div class="row g-2"><div class="col"><input class="form-control" name="q" value="<?=h($q)?>" placeholder="Pesquisar colaborador, máquina ou competência"></div><div class="col-md-2"><select class="form-select" name="machine_id"><option value="">Máquinas</option><?php foreach($machines as $m):?><option value="<?=$m['id']?>" <?=$mid===(int)$m['id']?'selected':''?>><?=h($m['code'])?></option><?php endforeach;?></select></div><div class="col-md-2"><select class="form-select" name="level"><option value="">Níveis</option><?php for($i=0;$i<=4;$i++):?><option value="<?=$i?>" <?=$lvl!==''&&(int)$lvl===$i?'selected':''?>><?=$i?></option><?php endfor;?></select></div><div class="col-auto"><button class="btn btn-primary">Filtrar</button></div></div></form><div class="row g-3 mb-3"><?php $autonomousCount=0;$trainerCount=0;$trainingCount=0;$expiredCount=0;foreach($rows as $cardRow){if((int)$cardRow['level']>=3){$autonomousCount++;}if((int)$cardRow['level']===4){$trainerCount++;}if((int)$cardRow['level']===1){$trainingCount++;}if(!empty($cardRow['expiry_date'])&&$cardRow['expiry_date']<date('Y-m-d')){$expiredCount++;}}$cards=array('Registos'=>count($rows),'Autónomos'=>$autonomousCount,'Formadores'=>$trainerCount,'Em formação'=>$trainingCount,'Avaliações vencidas'=>$expiredCount,'Máquinas sem cobertura'=>(int)$uncovered); foreach($cards as $l=>$v):?><div class="col-md-2"><div class="card card-body"><small class="text-muted"><?=h($l)?></small><strong class="fs-3"><?=$v?></strong></div></div><?php endforeach;?></div><div class="card mb-3"><div class="card-body"><h2 class="h5">Nova competência</h2><form method="post" class="row g-2"><?=csrf_input()?><div class="col-md-3"><select required class="form-select" name="user_id"><option value="">Colaborador</option><?php foreach($people as $p):?><option value="<?=$p['id']?>" <?=$uid===(int)$p['id']?'selected':''?>><?=h($p['name'])?></option><?php endforeach;?></select></div><div class="col-md-3"><select required class="form-select" name="machine_id"><option value="">Máquina</option><?php foreach($machines as $m):?><option value="<?=$m['id']?>" <?=$mid===(int)$m['id']?'selected':''?>><?=h($m['code'].' · '.$m['name'])?></option><?php endforeach;?></select></div><div class="col-md-2"><select class="form-select" name="level"><?php foreach([0=>'Sem conhecimento',1=>'Em formação',2=>'Com supervisão',3=>'Autónomo',4=>'Formador/especialista'] as $k=>$v):?><option value="<?=$k?>"><?=$k?> - <?=$v?></option><?php endforeach;?></select></div><div class="col-md-2"><input class="form-control" type="date" name="assessed_at" value="<?=date('Y-m-d')?>"></div><div class="col-md-2"><input class="form-control" type="date" name="expiry_date"></div><div class="col-12"><textarea class="form-control" name="notes" placeholder="Formação, limitações, evidências e notas"></textarea></div><div class="col-12"><button class="btn btn-primary">Guardar</button></div></form></div></div><div class="card"><div class="table-responsive"><table class="table mb-0"><tr><th>Colaborador</th><th>Departamento</th><th>Máquina</th><th>Nível</th><th>Avaliação</th><th>Validade</th><th>Notas</th></tr><?php foreach($rows as $r):?><tr><td><?=h($r['user_name'])?></td><td><?=h($r['department']??'')?></td><td><?=h($r['machine_code'].' · '.$r['machine_name'])?></td><td><?=h((string)$r['level'])?></td><td><?=h($r['assessed_at']??'')?></td><td><?=h($r['expiry_date']??'')?></td><td><?=h($r['notes']??'')?></td></tr><?php endforeach; if(!$rows):?><tr><td colspan="7">Sem competências para os filtros selecionados.</td></tr><?php endif;?></table></div></div></div><?php require __DIR__.'/partials/footer.php'; ?>
